using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

internal static class TestHelper
{
    public static SchoolContext CreateContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    public static T GetProperty<T>(object obj, string propertyName)
    {
        var prop = obj.GetType().GetProperty(propertyName);
        return (T)prop.GetValue(obj);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_ValidInputs_SetsPageIndex()
    {
        var items = new List<int> { 1, 2, 3 };

        var list = new PaginatedList<int>(items, 10, 2, 3);

        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 3, 4, DisplayName = "10 items / 3 per page = 4 pages (ceiling)")]
    [DataRow(9, 3, 3, DisplayName = "9 items / 3 per page = 3 pages (exact)")]
    [DataRow(1, 10, 1, DisplayName = "1 item / 10 per page = 1 page")]
    [DataRow(0, 10, 0, DisplayName = "0 items / 10 per page = 0 pages")]
    [DataRow(100, 10, 10, DisplayName = "100 items / 10 per page = 10 pages")]
    public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_WithItems_AddsAllItemsToList()
    {
        var items = new List<string> { "alpha", "beta", "gamma" };

        var list = new PaginatedList<string>(items, 3, 1, 3);

        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(2)]
    [DataRow(3)]
    [DataRow(10)]
    public void HasPreviousPage_PageGreaterThan1_ReturnsTrue(int pageIndex)
    {
        var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 10);

        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // 10 items, pageSize 5 => 2 pages. On page 2 (last page).
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // 10 items, pageSize 5 => 2 pages. On page 1.
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_FirstPage_ContainsFirstItems()
    {
        var source = Enumerable.Range(1, 10).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 3);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(2, result[1]);
        Assert.AreEqual(3, result[2]);
    }

    [TestMethod]
    public void Create_LastPage_ContainsRemainingItems()
    {
        var source = Enumerable.Range(1, 7).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 3);

        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(7, result[0]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.AreEqual(1, result.PageIndex);
    }

    [TestMethod]
    public void Create_ExactlyOnePage_HasNoNextOrPrevious()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class ModelTests
{
    [TestMethod]
    public void Person_FullName_ReturnsLastNameCommaFirstName()
    {
