using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _service;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        // Drain the shared static queue to avoid cross-test interference
        while (_service.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _service?.Dispose();
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var result = _service.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesWithCorrectProperties()
    {
        _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "TestUser");

        var notification = _service.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("1050", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("TestUser", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "42", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Student (ID: 42) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_UsesNameInMessage()
    {
        _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Course 'TestCourse' has been created", DisplayName = "CREATE message")]
    [DataRow(EntityOperation.UPDATE, "Course 'TestCourse' has been updated", DisplayName = "UPDATE message")]
    [DataRow(EntityOperation.DELETE, "Course 'TestCourse' has been deleted", DisplayName = "DELETE message")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        _service.SendNotification("Course", "1", "TestCourse", operation);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student (ID: 1) has been created", DisplayName = "CREATE without name")]
    [DataRow(EntityOperation.UPDATE, "Student (ID: 1) has been updated", DisplayName = "UPDATE without name")]
    [DataRow(EntityOperation.DELETE, "Student (ID: 1) has been deleted", DisplayName = "DELETE without name")]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage(EntityOperation operation, string expectedMessage)
    {
        _service.SendNotification("Student", "1", operation);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _service.SendNotification("Course", "1", "Test", EntityOperation.CREATE, null);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
        _service.SendNotification("Course", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Course", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _service.ReceiveNotification();

        Assert.IsTrue(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
        Assert.IsTrue(notification.CreatedAt <= after, $"CreatedAt {notification.CreatedAt} should be <= {after}");
    }

    [TestMethod]
    public void SendReceive_MultipleNotifications_FIFOOrder()
    {
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();
        var fourth = _service.ReceiveNotification();

        Assert.AreEqual("A", first.EntityType);
        Assert.AreEqual("B", second.EntityType);
        Assert.AreEqual("C", third.EntityType);
        Assert.IsNull(fourth);
    }

    [TestMethod]
    public void MarkAsRead_AnyId_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        _service.MarkAsRead(1);
        _service.MarkAsRead(0);
        _service.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_MultipleCalls_DoesNotThrow()
    {
        var service = new NotificationService();
        service.Dispose();
        service.Dispose();
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "5", "   ", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        // whitespace-only display name falls through to ID-based message
        Assert.AreEqual("New Student (ID: 5) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Student", "5", "", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.AreEqual("New Student (ID: 5) has been created", notification.Message);
    }
}

