using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_ValidInputs_SetsPageIndex()
    {
        var items = new List<int> { 1, 2, 3 };

        var list = new PaginatedList<int>(items, 10, 2, 3);

        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 3, 4, DisplayName = "10 items / 3 per page = 4 pages (ceiling)")]
    [DataRow(9, 3, 3, DisplayName = "9 items / 3 per page = 3 pages (exact)")]
    [DataRow(1, 10, 1, DisplayName = "1 item / 10 per page = 1 page")]
    [DataRow(0, 10, 0, DisplayName = "0 items / 10 per page = 0 pages")]
    [DataRow(100, 10, 10, DisplayName = "100 items / 10 per page = 10 pages")]
    public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_WithItems_AddsAllItemsToList()
    {
        var items = new List<string> { "alpha", "beta", "gamma" };

        var list = new PaginatedList<string>(items, 3, 1, 3);

        Assert.AreEqual(3, list.Count);
        Assert.AreEqual("alpha", list[0]);
        Assert.AreEqual("beta", list[1]);
        Assert.AreEqual("gamma", list[2]);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(2)]
    [DataRow(3)]
    [DataRow(10)]
    public void HasPreviousPage_PageGreaterThan1_ReturnsTrue(int pageIndex)
    {
        var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 10);

        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // 10 items, pageSize 5 => 2 pages. On page 2 (last page).
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // 10 items, pageSize 5 => 2 pages. On page 1.
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

