using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelper.CreateContext();
        _controller = new NotificationsController(_context);
        // Drain the shared static notification queue to avoid cross-test interference
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    // --- GetNotifications ---

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        var success = TestHelper.GetProperty<bool>(result.Value, "success");
        var count = TestHelper.GetProperty<int>(result.Value, "count");
        Assert.IsTrue(success);
        Assert.AreEqual(0, count);
    }

    [TestMethod]
    public void GetNotifications_WithQueuedNotifications_ReturnsNotifications()
    {
        // Enqueue notifications via the shared static queue
        var svc = new NotificationService();
        svc.SendNotification("Course", "1", "Chemistry", EntityOperation.CREATE);
        svc.SendNotification("Student", "2", "John Doe", EntityOperation.UPDATE);

        var result = _controller.GetNotifications();

        Assert.IsNotNull(result.Value);
        var success = TestHelper.GetProperty<bool>(result.Value, "success");
        var count = TestHelper.GetProperty<int>(result.Value, "count");
        Assert.IsTrue(success);
        Assert.AreEqual(2, count);
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        var result = _controller.GetNotifications();

        var count = TestHelper.GetProperty<int>(result.Value, "count");
        Assert.AreEqual(10, count);
    }

    [TestMethod]
    public void GetNotifications_DrainsQueue()
    {
        var svc = new NotificationService();
        svc.SendNotification("Course", "1", EntityOperation.CREATE);

        // First call should get the notification
        var result1 = _controller.GetNotifications();
        var count1 = TestHelper.GetProperty<int>(result1.Value, "count");
        Assert.AreEqual(1, count1);

        // Second call should get empty queue
        var result2 = _controller.GetNotifications();
        var count2 = TestHelper.GetProperty<int>(result2.Value, "count");
        Assert.AreEqual(0, count2);
    }

    // --- MarkAsRead ---

    [TestMethod]
    public void MarkAsRead_ValidId_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        var success = TestHelper.GetProperty<bool>(result.Value, "success");
        Assert.IsTrue(success);
    }

    [TestMethod]
    public void MarkAsRead_AnyId_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        var result1 = _controller.MarkAsRead(0);
        var result2 = _controller.MarkAsRead(999);

        Assert.IsNotNull(result1);
        Assert.IsNotNull(result2);
    }

    // --- Index ---

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
    }
}

