+    [TestMethod]
+    public void Initialize_Enrollments_HaveGrades()
+    {
+        using var context = TestHelper.CreateContext();
+
+        DbInitializer.Initialize(context);
+
+        // At least some enrollments should have grades (not all - Arturo's Chemistry has no grade)
+        var withGrades = context.Enrollments.Count(e => e.Grade != null);
